ADD COLUMN IF NOT EXISTS passwordHash VARCHAR(255),
ADD COLUMN IF NOT EXISTS rememberToken VARCHAR(255),
ADD COLUMN IF NOT EXISTS rememberTokenExpiresAt DATETIME,
MODIFY COLUMN openId VARCHAR(64),
